                else if (char == 0x09) _unsafeWriteBytesOffset(output, outputLength++, "t");
                else if (char == 0x0a) _unsafeWriteBytesOffset(output, outputLength++, "n");
                else if (char == 0x0c) _unsafeWriteBytesOffset(output, outputLength++, "f");
                else if (char == 0x0d) _unsafeWriteBytesOffset(output, outputLength++, "r");
                else if (char == 0x5c) _unsafeWriteBytesOffset(output, outputLength++, "\\");
                else if (char == 0x22) {
                    // solhint-disable-next-line quotes
                    _unsafeWriteBytesOffset(output, outputLength++, '"');
                } else {
                    // U+0000 to U+001F without short form: output \u00XX
                    _unsafeWriteBytesOffset(output, outputLength++, "u");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char >> 4]);
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char & 0x0f]);
                }
            } else {
                _unsafeWriteBytesOffset(output, outputLength++, bytes1(char));
            }
        }
        // write the actual length and reserve memory
        assembly ("memory-safe") {
            mstore(output, outputLength)
            mstore(0x40, add(output, add(outputLength, 0x20)))
        }

        return string(output);
    }

    /**
     * @dev Reads a bytes32 from a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeReadBytesOffset(bytes memory buffer, uint256 offset) private pure returns (bytes32 value) {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            value := mload(add(add(buffer, 0x20), offset))
        }
    }

    /**
     * @dev Write a bytes1 to a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeWriteBytesOffset(bytes memory buffer, uint256 offset, bytes1 value) private pure {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            mstore8(add(add(buffer, 0x20), offset), shr(248, value))
        }
    }
}

contracts/BottomProtectionVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title BottomProtectionVault
 * @notice Buy-in principal return vault — 30 % of CNOVA tax BNB flows here.
 *
 * Mechanism
 * ─────────
 * Users record their weighted average buy price on-chain via `recordPurchase()`.
 * When they wish to redeem protection, they:
 *   1. Obtain a signed price attestation from the off-chain watcher service
 *      (POST /api/price-signature?user=0x...).
 *   2. Call `redeem(qty, refPrice, deadline, v, r, s)`.
 *
 * Loss tier table (lossRate = (weightedBuyPrice - refPrice) / weightedBuyPrice)
 * ──────────────────────────────────────────────────────────────────────────────
 *   lossRate < 50 %          → 0 % principal returned (not triggered)
 *   50 % ≤ lossRate < 60 %   → 30 % principal returned
 *   60 % ≤ lossRate < 70 %   → 50 % principal returned
 *   70 % ≤ lossRate < 80 %   → 60 % principal returned
 *   80 % ≤ lossRate < 90 %   → 70 % principal returned
 *   90 % ≤ lossRate < 100 %  → 80 % principal returned
 *   refPrice == 0 OR emergencyZero enabled → 100 % principal returned
 *
 * Payout formula:
 *   payoutBNB = redeemQty × weightedBuyPrice × payoutRatio / 1e18
 *
 * Redeemed tokens are burned to BURN_ADDRESS (0x…dEaD) — never re-enter market.
 *
 * Signed price attestation (EIP-191 simple hash)
 * ───────────────────────────────────────────────
 *   digest = keccak256(abi.encodePacked(
 *       "\x19Ethereum Signed Message:\n32",
 *       keccak256(abi.encodePacked(
 *           "BottomProtection",
 *           block.chainid,
 *           address(this),
 *           refPrice,
 *           nonces[user],
 *           deadline
 *       ))
 *   ))
 *   require ecrecover(digest, v, r, s) == signer
 *
 * Deployment
 * ──────────
 *   constructor(cnova, owner)
 *   Owner calls setSigner(watcherAddress) after deploy.
 *   TaxReceiver routes 30 % here via notifyReward().
 */
contract BottomProtectionVault is Ownable, ReentrancyGuard {

    // ─── Constants ────────────────────────────────────────────────────────────
    address public constant BURN_ADDRESS = 0x000000000000000000000000000000000000dEaD;
    uint256 private constant PRECISION   = 1e18;

    // ─── State ────────────────────────────────────────────────────────────────
    IERC20  public cnova;
    address public signer;          // Off-chain watcher public key
    bool    public emergencyZero;   // Owner enables → 100 % payout allowed

    uint256 public totalReceived;   // Cumulative BNB received from TaxReceiver
    uint256 public totalPaidOut;    // Cumulative BNB paid to users

    /// @dev Weighted average buy price per user (BNB/CNOVA, 1e18 precision)
    mapping(address => uint256) public weightedBuyPrice;
    /// @dev Number of CNOVA tokens eligible for protection (1e18 precision)
    mapping(address => uint256) public protectedBalance;
    /// @dev Replay-protection nonce per user, incremented on each redeem
    mapping(address => uint256) public nonces;

    // ─── Events ───────────────────────────────────────────────────────────────
    event RewardReceived(uint256 amount);
    event PurchaseRecorded(address indexed user, uint256 qty, uint256 price, uint256 newWeightedPrice);
    event Redeemed(address indexed user, uint256 qty, uint256 refPrice, uint256 lossRateBps, uint256 payoutBps, uint256 payoutBnb);
    event SignerUpdated(address indexed prev, address indexed next);
    event EmergencyZeroSet(bool enabled);
    event EmergencyWithdrawn(address indexed to, uint256 amount);

    // ─── Errors ───────────────────────────────────────────────────────────────
    error ZeroAddress();
    error ZeroAmount();
    error SignatureExpired();
    error InvalidSignature();
    error LossBelowThreshold();
    error InsufficientProtectedBalance();
    error InsufficientVaultBalance();
    error TransferFailed();
    error NoBuyPriceRecorded();

    // ─── Constructor ─────────────────────────────────────────────────────────
    constructor(address _cnova, address _owner) Ownable(_owner) {
        if (_cnova == address(0)) revert ZeroAddress();
        cnova = IERC20(_cnova);
    }

    // ─── BNB receive (from TaxReceiver) ──────────────────────────────────────
    receive() external payable {
        totalReceived += msg.value;
        emit RewardReceived(msg.value);
    }

    fallback() external payable {
        totalReceived += msg.value;
        emit RewardReceived(msg.value);
    }

    /// @notice Called by TaxReceiver via notifyReward() — same as plain receive.
    function notifyReward() external payable {
        totalReceived += msg.value;
        emit RewardReceived(msg.value);
    }

    // ─── User: record purchase ────────────────────────────────────────────────

    /**
     * @notice Record a CNOVA purchase to establish or update weighted buy price.
     * @param qty         Amount of CNOVA purchased (wei, 1e18 = 1 CNOVA).
     * @param pricePerToken BNB paid per CNOVA (wei per 1e18 CNOVA, i.e. 1e18 precision).
     *
     * Weighted average:
     *   newPrice = (oldPrice × oldQty + pricePerToken × qty) / (oldQty + qty)
     *
     * Can only increase protectedBalance — selling does NOT reduce it here;
     * the vault penalises the redeemable qty in `redeem()`.
     */
    function recordPurchase(uint256 qty, uint256 pricePerToken) external {
        if (qty == 0) revert ZeroAmount();
        if (pricePerToken == 0) revert ZeroAmount();

        address user    = msg.sender;
        uint256 oldQty   = protectedBalance[user];
        uint256 oldPrice = weightedBuyPrice[user];

        uint256 newPrice;
        if (oldQty == 0) {
            newPrice = pricePerToken;
        } else {
            // Weighted average — safe from overflow given realistic token amounts
            newPrice = (oldPrice * oldQty + pricePerToken * qty) / (oldQty + qty);
        }

        protectedBalance[user] += qty;
        weightedBuyPrice[user]  = newPrice;

        emit PurchaseRecorded(user, qty, pricePerToken, newPrice);
    }

    // ─── User: redeem protection ──────────────────────────────────────────────

    /**
     * @notice Sell `redeemQty` CNOVA to the vault for BNB compensation.
     *
     * @param redeemQty  CNOVA amount to redeem (must be ≤ protectedBalance).
     * @param refPrice   Current CNOVA price in BNB (1e18 precision), attested by signer.
     * @param deadline   Signature expiry (unix timestamp).
     * @param v          ECDSA v.
     * @param r          ECDSA r.
     * @param s          ECDSA s.
     *
     * The redeemed CNOVA tokens are transferred from the user to BURN_ADDRESS.
     * The user receives BNB from the vault.
     */
    function redeem(
        uint256 redeemQty,
        uint256 refPrice,
        uint256 deadline,
        uint8 v, bytes32 r, bytes32 s
    ) external nonReentrant {
        if (redeemQty == 0) revert ZeroAmount();
        if (block.timestamp > deadline) revert SignatureExpired();

        address user = msg.sender;
        if (weightedBuyPrice[user] == 0) revert NoBuyPriceRecorded();
        if (protectedBalance[user] < redeemQty) revert InsufficientProtectedBalance();

        // ── Verify watcher signature ─────────────────────────────────────────
        bytes32 innerHash = keccak256(abi.encodePacked(
            "BottomProtection",
            block.chainid,
            address(this),
            refPrice,
            nonces[user],
            deadline
        ));
        bytes32 digest = keccak256(abi.encodePacked("\x19Ethereum Signed Message:\n32", innerHash));
        address recovered = ecrecover(digest, v, r, s);
        if (recovered == address(0) || recovered != signer) revert InvalidSignature();

        // Consume nonce
        nonces[user]++;

        // ── Compute loss rate (basis points, 1 bp = 0.01 %) ─────────────────
        uint256 buyPrice = weightedBuyPrice[user];
        uint256 lossRateBps;

        if (refPrice == 0 || emergencyZero) {
            lossRateBps = 10000; // 100 %
        } else if (refPrice >= buyPrice) {
            // No loss — revert
            revert LossBelowThreshold();
        } else {
            // lossRateBps = (buyPrice - refPrice) * 10000 / buyPrice
            lossRateBps = ((buyPrice - refPrice) * 10000) / buyPrice;
        }

        // ── Tier lookup → payout basis points ────────────────────────────────
        uint256 payoutBps = _payoutBps(lossRateBps);
        if (payoutBps == 0) revert LossBelowThreshold();

        // ── Compute BNB payout ────────────────────────────────────────────────
        // payoutBnb = redeemQty * buyPrice * payoutBps / 1e18 / 10000
        // redeemQty in 1e18 CNOVA, buyPrice in wei/CNOVA (1e18 precision)
        // → redeemQty * buyPrice = wei² units → divide by 1e18 to get wei
        uint256 payoutBnb = (redeemQty * buyPrice / PRECISION) * payoutBps / 10000;

        if (payoutBnb == 0) revert ZeroAmount();
        if (address(this).balance < payoutBnb) revert InsufficientVaultBalance();

        // ── State updates ────────────────────────────────────────────────────
        protectedBalance[user] -= redeemQty;
        totalPaidOut           += payoutBnb;

        // ── Token burn ───────────────────────────────────────────────────────
        // Transfer CNOVA from user → BURN_ADDRESS (user must approve first)
        bool tokenOk = cnova.transferFrom(user, BURN_ADDRESS, redeemQty);
        if (!tokenOk) revert TransferFailed();

        // ── BNB payout ───────────────────────────────────────────────────────
        (bool bnbOk, ) = user.call{value: payoutBnb}("");
        if (!bnbOk) revert TransferFailed();

        emit Redeemed(user, redeemQty, refPrice, lossRateBps, payoutBps, payoutBnb);
    }

    // ─── Views ────────────────────────────────────────────────────────────────

    /**
     * @notice Estimate payout for a given user, qty, and refPrice.
     *         Does NOT check signature — for UI preview only.
     */
    function estimatedPayout(
        address user,
        uint256 qty,
        uint256 refPrice
    ) external view returns (uint256 payoutBnb, uint256 lossRateBps, uint256 payoutBps) {
        uint256 buyPrice = weightedBuyPrice[user];
        if (buyPrice == 0 || qty == 0) return (0, 0, 0);

        if (refPrice == 0 || emergencyZero) {
            lossRateBps = 10000;
        } else if (refPrice >= buyPrice) {
            return (0, 0, 0);
        } else {
            lossRateBps = ((buyPrice - refPrice) * 10000) / buyPrice;
        }

        payoutBps  = _payoutBps(lossRateBps);
        payoutBnb  = (qty * buyPrice / PRECISION) * payoutBps / 10000;
    }

    function vaultBalance() external view returns (uint256) {
        return address(this).balance;
    }

    // ─── Internal tier lookup ─────────────────────────────────────────────────

    function _payoutBps(uint256 lossRateBps) internal pure returns (uint256) {
        if (lossRateBps >= 10000)  return 10000; // 100 % — emergency/zero
        if (lossRateBps >= 9000)   return 8000;  // 90–100 % loss → 80 % returned
        if (lossRateBps >= 8000)   return 7000;  // 80–90 %  → 70 %
        if (lossRateBps >= 7000)   return 6000;  // 70–80 %  → 60 %
        if (lossRateBps >= 6000)   return 5000;  // 60–70 %  → 50 %
        if (lossRateBps >= 5000)   return 3000;  // 50–60 %  → 30 %
        return 0;                                 // < 50 %   → not triggered
    }

    // ─── Owner management ─────────────────────────────────────────────────────

    function setSigner(address _signer) external onlyOwner {
        if (_signer == address(0)) revert ZeroAddress();
        emit SignerUpdated(signer, _signer);
        signer = _signer;
    }

    function setEmergencyZero(bool _enabled) external onlyOwner {
        emergencyZero = _enabled;
        emit EmergencyZeroSet(_enabled);
    }

    // ─── Emergency ────────────────────────────────────────────────────────────

    function emergencyWithdraw() external onlyOwner nonReentrant {
        uint256 bal = address(this).balance;
        if (bal == 0) revert InsufficientVaultBalance();
        (bool ok, ) = owner().call{value: bal}("");
        if (!ok) revert TransferFailed();
        emit EmergencyWithdrawn(owner(), bal);
    }
}

contracts/CNovaBridge.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/cryptography/MessageHashUtils.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";

interface IWrappedToken {
    function mint(address to, uint256 amount) external;
    function burnFromBridge(address from, uint256 amount) external;
}

contract CNovaBridge is Ownable {
    using SafeERC20 for IERC20;
    using ECDSA for bytes32;
    using MessageHashUtils for bytes32;

    address public validator;
    uint256 public flatFeeWei;
    uint256 public nonce;

    struct TokenRoute {
        address remoteToken;
        bool wrapped;
        bool active;
    }

    mapping(address => TokenRoute) public tokenRoutes;
    mapping(bytes32 => bool) public processedTransfers;

    event TokenRouteConfigured(
        address indexed localToken,
        address indexed remoteToken,
        bool wrapped
    );
    event BridgeTransferInitiated(
        bytes32 indexed transferId,
        address indexed sender,
        address localToken,
        uint256 amount,
        uint256 targetChainId,
        bytes32 recipientBytes32
    );
    event BridgeTransferCompleted(
        bytes32 indexed transferId,
        address indexed recipient,
        address localToken,
        uint256 amount
    );
    event ValidatorUpdated(address indexed oldValidator, address indexed newValidator);
    event FlatFeeUpdated(uint256 oldFee, uint256 newFee);

    error InvalidValidator();
    error InsufficientFee();
    error RouteNotActive();
    error TransferAlreadyProcessed();
    error InvalidSignature();
    error ZeroAmount();

    constructor(
        address initialOwner,
        address initialValidator,
        uint256 initialFlatFeeWei
    ) Ownable(initialOwner) {
        validator = initialValidator;
        flatFeeWei = initialFlatFeeWei;
    }

    function setValidator(address newValidator) external onlyOwner {
        if (newValidator == address(0)) revert InvalidValidator();
        emit ValidatorUpdated(validator, newValidator);
        validator = newValidator;
    }

    function setFlatFee(uint256 newFee) external onlyOwner {
        emit FlatFeeUpdated(flatFeeWei, newFee);
        flatFeeWei = newFee;
    }

    function configureRoute(
        address localToken,
        address remoteToken,
        bool wrapped
    ) external onlyOwner {
        tokenRoutes[localToken] = TokenRoute({
            remoteToken: remoteToken,
            wrapped: wrapped,
            active: true
        });
        emit TokenRouteConfigured(localToken, remoteToken, wrapped);
    }

    function bridgeOut(
        address localToken,
        uint256 amount,
        uint256 targetChainId,
        bytes32 recipientBytes32
    ) external payable returns (bytes32 transferId) {
        if (amount == 0) revert ZeroAmount();
        if (msg.value < flatFeeWei) revert InsufficientFee();

        TokenRoute memory route = tokenRoutes[localToken];
        if (!route.active) revert RouteNotActive();

        transferId = keccak256(
            abi.encodePacked(
                block.chainid,
                msg.sender,
                localToken,
                amount,
                targetChainId,
                recipientBytes32,
                nonce++
            )
        );

        if (route.wrapped) {
            IWrappedToken(localToken).burnFromBridge(msg.sender, amount);
        } else {
            IERC20(localToken).safeTransferFrom(msg.sender, address(this), amount);
        }

        emit BridgeTransferInitiated(
            transferId,
            msg.sender,
            localToken,
            amount,
            targetChainId,
            recipientBytes32
        );
    }

    function completeTransfer(
        bytes calldata message,
        bytes calldata validatorSignature
    ) external {
        (
            bytes32 transferId,
            address localToken,
            uint256 amount,
            address recipient
        ) = abi.decode(message, (bytes32, address, uint256, address));

        if (processedTransfers[transferId]) revert TransferAlreadyProcessed();

        bytes32 messageHash = keccak256(message);
        bytes32 ethSignedHash = messageHash.toEthSignedMessageHash();
        address signer = ethSignedHash.recover(validatorSignature);

        if (signer != validator) revert InvalidSignature();

        processedTransfers[transferId] = true;

        TokenRoute memory route = tokenRoutes[localToken];
        if (!route.active) revert RouteNotActive();

        if (route.wrapped) {
            IWrappedToken(localToken).mint(recipient, amount);
        } else {
            IERC20(localToken).safeTransfer(recipient, amount);
        }

        emit BridgeTransferCompleted(transferId, recipient, localToken, amount);
    }

    function withdrawFees(address payable to) external onlyOwner {
        (bool success, ) = to.call{value: address(this).balance}("");
        require(success, "Fee withdrawal failed");
    }

    receive() external payable {}
}

contracts/CNovaWrappedToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract CNovaWrappedToken is ERC20, Ownable {
    uint8 private _customDecimals;
    address public bridge;

    error OnlyBridge();
    error ZeroAddress();

    event BridgeUpdated(address indexed oldBridge, address indexed newBridge);

    modifier onlyBridge() {
        if (msg.sender != bridge) revert OnlyBridge();
        _;
    }

    constructor(
        string memory name_,
        string memory symbol_,
        uint8 decimals_,
        address initialOwner_
    ) ERC20(name_, symbol_) Ownable(initialOwner_) {
        _customDecimals = decimals_;
    }

    function decimals() public view override returns (uint8) {
        return _customDecimals;
    }

    function setBridge(address newBridge) external onlyOwner {
        if (newBridge == address(0)) revert ZeroAddress();
        emit BridgeUpdated(bridge, newBridge);
        bridge = newBridge;
    }

    function mint(address to, uint256 amount) external onlyBridge {
        _mint(to, amount);
    }

    function burnFromBridge(address from, uint256 amount) external onlyBridge {
        _burn(from, amount);
    }
}

contracts/HolderDividend.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title HolderDividend  v2
 * @notice Phase 1 holder dividend contract — time-weighted batch settlement model.
 *
 * ── Mechanism ────────────────────────────────────────────────────────────────
 *   • Holders with ≥ minimumBalance CNOVA call register().
 *     Balance is snapshotted as registeredBalance; timer starts (weightedStartTs = now).
 *
 *   • BNB arrives from TaxReceiver via notifyReward(). At that moment:
 *       1. Total weight = Σ(balance_i × elapsed_i) over all registered users.
 *       2. A Settlement record is stored: { bnbAmount, totalWeight, settledAt }.
 *       3. Any previously forfeited BNB is swept into this settlement.
 *
 *   • Users call claim() at any time. For each unclaimed settlement:
 *       userShare = (userBalance × (settlement.settledAt − user.weightedStartTs))
 *                  / settlement.totalWeight × settlement.bnbAmount
 *     Claiming does NOT reset weightedStartTs.
 *
 *   • Top-up (buy more):
 *       Keeper calls updateBalance(user). Contract reads token.balanceOf(user).
 *       If balance increased: weightedStartTs slides forward via weighted average
 *       (new tokens dilute the clock, but old tokens keep their full elapsed time).
 *       registeredBalance is updated; nextSettlementIdx unchanged.
 *
 *   • Sell detection (permissionless keeper):
 *       Keeper calls updateBalance(user) whenever it sees an outgoing Transfer.
 *       If token.balanceOf(user) < registeredBalance → _invalidate:
 *         - User is removed from the pool.
 *         - Their share of all unclaimed past settlements is forfeited → forfeitedPool.
 *         - forfeitedPool is swept into the NEXT settlement automatically.
 *
 * ── Sell invalidation model ───────────────────────────────────────────────────
 *   NOT a token hook (CNOVA contract is unmodified).
 *   INSTEAD: off-chain keeper (server/dividend-keeper.ts) watches ERC-20 Transfer
 *   events on BSC and calls updateBalance(from) for any registered user.
 *   updateBalance is PERMISSIONLESS — anyone can call for any address.
 *   No onlyOwner forceDeregister as main flow.
 *
 * ── Deployment order ──────────────────────────────────────────────────────────
 *   1. Deploy HolderDividend (CNOVA address, minimumBalance, owner)
 *   2. Deploy TaxReceiver (HolderDividend address, marketingWallet, owner)
 *   3. HolderDividend.setTaxReceiver(TaxReceiver address)
 *   4. After token graduates: set TaxReceiver as token tax address
 *   5. Call TaxReceiver.flush() periodically to trigger settlements
 */
contract HolderDividend is Ownable, ReentrancyGuard {

    IERC20 public immutable token;
    uint256 public minimumBalance;
    address public taxReceiver;

    // ─── Settlement records ──────────────────────────────────────────────────
    struct Settlement {
        uint256 bnbAmount;     // total BNB available in this settlement (incl. forfeitures)
        uint256 totalWeight;   // Σ(balance_i × elapsed_i) at settledAt
        uint256 settledAt;     // block.timestamp when settlement was created
    }

    Settlement[] public settlements;

    /// @notice BNB forfeited by invalidated users — swept into next settlement
    uint256 public forfeitedPool;

    // ─── User state ──────────────────────────────────────────────────────────
    struct UserInfo {
        uint256 registeredBalance;  // CNOVA tracked by contract (updated on top-up)
        uint256 weightedStartTs;    // effective holding start time (weighted avg on top-up)
        uint256 nextSettlementIdx;  // index of next settlement to claim (0 = from beginning)
        uint256 totalClaimed;       // lifetime BNB claimed by this user
        uint256 registeredAt;       // original registration timestamp
        bool    registered;
    }

    mapping(address => UserInfo) public users;

    /// @notice Full list of addresses that have ever registered.
    ///         Used by off-chain keeper for enumeration. May contain invalidated users.
    address[] public registeredList;

    // ─── Global totals ───────────────────────────────────────────────────────
    uint256 public totalRegisteredBalance;  // sum of all active registeredBalance values
    uint256 public totalReceived;           // all BNB ever received
    uint256 public totalClaimedGlobal;      // all BNB ever paid out

    // ─── Events ──────────────────────────────────────────────────────────────
    event Registered(address indexed user, uint256 balance);
    event BalanceUpdated(address indexed user, uint256 oldBalance, uint256 newBalance, uint256 newWeightedStartTs);
    event Invalidated(address indexed user, uint256 forfeitedBnb);
    event BatchSettled(uint256 indexed idx, uint256 bnbAmount, uint256 totalWeight, uint256 settledAt);
    event Claimed(address indexed user, uint256 amount, uint256 nextIdx);
    event TaxReceiverUpdated(address indexed prev, address indexed next);
    event MinimumBalanceUpdated(uint256 prev, uint256 next);

    // ─── Errors ──────────────────────────────────────────────────────────────
    error AlreadyRegistered();
    error NotRegistered();
    error InsufficientBalance(uint256 have, uint256 need);
    error NothingToClaim();
    error TransferFailed();
    error ZeroAddress();

    // ─── Constructor ─────────────────────────────────────────────────────────

    /**
     * @param _token          CNOVA ERC-20 address (BSC mainnet: 0x0a9c...7777)
     * @param _minimumBalance Minimum CNOVA to register, in wei (e.g. 200_000 * 1e18)
     * @param _owner          Contract owner (multisig recommended)
     */
    constructor(
        address _token,
        uint256 _minimumBalance,
        address _owner
    ) Ownable(_owner) {
        if (_token == address(0)) revert ZeroAddress();
        token = IERC20(_token);
        minimumBalance = _minimumBalance;
    }

    // ─── BNB inflow ──────────────────────────────────────────────────────────

    /**
     * @notice Receive BNB. Incoming BNB waits in contract until notifyReward() creates a settlement.
     */
    receive() external payable {
        totalReceived += msg.value;
    }

    /**
     * @notice Called by TaxReceiver (or any sender) to trigger a settlement.
     *         Sweeps ALL available BNB (msg.value + forfeitedPool) into one settlement.
     *         If no users are registered yet, BNB stays in forfeitedPool for the next call.
     */
    function notifyReward() external payable {
        totalReceived += msg.value;
        uint256 bnbToSettle = msg.value + forfeitedPool;

        if (bnbToSettle == 0) return;

        uint256 tw = _computeTotalWeight();

        if (tw == 0) {
            // No registered users with elapsed time; keep BNB for next settlement
            forfeitedPool = bnbToSettle;
            return;
        }

        forfeitedPool = 0;

        uint256 idx = settlements.length;
        settlements.push(Settlement({
            bnbAmount:   bnbToSettle,
            totalWeight: tw,
            settledAt:   block.timestamp
        }));

        emit BatchSettled(idx, bnbToSettle, tw, block.timestamp);
    }

    // ─── Registration ────────────────────────────────────────────────────────

    /**
     * @notice Join the dividend pool.
     *         Caller must hold ≥ minimumBalance CNOVA at call time.
     *         Timer starts from this block. Eligible from the NEXT settlement onward.
     */
    function register() external nonReentrant {
        if (users[msg.sender].registered) revert AlreadyRegistered();

        uint256 bal = token.balanceOf(msg.sender);
        if (bal < minimumBalance) revert InsufficientBalance(bal, minimumBalance);

        users[msg.sender] = UserInfo({
            registeredBalance:  bal,
            weightedStartTs:    block.timestamp,
            nextSettlementIdx:  settlements.length, // only claims future settlements
            totalClaimed:       0,
            registeredAt:       block.timestamp,
            registered:         true
        });

        totalRegisteredBalance += bal;
        registeredList.push(msg.sender);

        emit Registered(msg.sender, bal);
    }

    // ─── Balance update (permissionless — keeper calls this) ─────────────────

    /**
     * @notice Sync a registered user's balance against the live token.balanceOf().
     *         Anyone may call for any address. This is how sell-detection works.
     *
     *   token.balanceOf(user) < registeredBalance  →  sold tokens → invalidate
     *   token.balanceOf(user) > registeredBalance  →  bought more → top-up (weighted avg start)
     *   token.balanceOf(user) == registeredBalance →  no-op
     */
    function updateBalance(address user) external nonReentrant {
        UserInfo storage u = users[user];
        if (!u.registered) return;

        uint256 live = token.balanceOf(user);

        if (live < u.registeredBalance) {
            // Any decrease = disqualify immediately
            _invalidate(user, u);
            return;
        }

        if (live > u.registeredBalance) {
            // Top-up: slide the effective start forward via weighted average.
            // Old tokens keep their elapsed time; new tokens start fresh.
            uint256 old    = u.registeredBalance;
            uint256 added  = live - old;
            uint256 now_   = block.timestamp;

            // weightedStart = (old × oldStart + added × now) / live
            uint256 newStart = (old * u.weightedStartTs + added * now_) / live;

            totalRegisteredBalance = totalRegisteredBalance - old + live;
            u.registeredBalance  = live;
            u.weightedStartTs    = newStart;

            emit BalanceUpdated(user, old, live, newStart);
        }
        // Equal → no-op (gas-efficient)
    }

    // ─── Claim ───────────────────────────────────────────────────────────────

    /**
     * @notice Claim all pending BNB from past settlements.
     *         Does NOT reset weightedStartTs — timer keeps running.
     */
    function claim() external nonReentrant {
        UserInfo storage u = users[msg.sender];
        if (!u.registered) revert NotRegistered();

        uint256 payout = _computePending(u);
        if (payout == 0) revert NothingToClaim();

        uint256 newIdx = settlements.length;
        u.nextSettlementIdx = newIdx;
        u.totalClaimed      += payout;
        totalClaimedGlobal  += payout;

        _transferBnb(msg.sender, payout);
        emit Claimed(msg.sender, payout, newIdx);
    }

    // ─── Views ───────────────────────────────────────────────────────────────

    /**
     * @notice Pending BNB claimable by a user.
     */
    function pendingReward(address user) external view returns (uint256) {
        UserInfo storage u = users[user];
        if (!u.registered) return 0;
        return _computePending(u);
    }

    /**
     * @notice A user's current weight in weight-seconds (balance × elapsed seconds).
     */
    function currentWeight(address user) external view returns (uint256) {
        UserInfo storage u = users[user];
        if (!u.registered) return 0;
        uint256 elapsed = block.timestamp > u.weightedStartTs
            ? block.timestamp - u.weightedStartTs : 0;
        return u.registeredBalance * elapsed;
    }

    /**
     * @notice Total weight of all registered users right now.
     */
    function totalCurrentWeight() external view returns (uint256) {
        return _computeTotalWeight();
    }

    /**
     * @notice A user's weight share as (numerator, denominator).
     *         Share % = numerator * 100 / denominator.
     */
    function userWeightShare(address user)
        external
        view
        returns (uint256 numerator, uint256 denominator)
    {
        UserInfo storage u = users[user];
        if (!u.registered) return (0, 1);
        uint256 elapsed = block.timestamp > u.weightedStartTs
            ? block.timestamp - u.weightedStartTs : 0;
        uint256 uw = u.registeredBalance * elapsed;
        uint256 tw = _computeTotalWeight();
        return (uw, tw == 0 ? 1 : tw);
    }

    /**
     * @notice Full user state — for frontend display.
     * @return registered         true if in the pool
     * @return registeredBalance  snapshotted CNOVA balance
     * @return weightedStartTs    effective holding start timestamp
     * @return holdingSeconds     seconds since weightedStartTs
     * @return registeredAt       original registration timestamp
     * @return nextSettlementIdx  next settlement to claim
     * @return userTotalClaimed   lifetime BNB claimed
     * @return pendingBnb         claimable right now
     */
    function userInfo(address user)
        external
        view
        returns (
            bool     registered,
            uint256  registeredBalance,
            uint256  weightedStartTs,
            uint256  holdingSeconds,
            uint256  registeredAt,
            uint256  nextSettlementIdx,
            uint256  userTotalClaimed,
            uint256  pendingBnb
        )
    {
        UserInfo storage u = users[user];
        uint256 elapsed = (u.registered && block.timestamp > u.weightedStartTs)
            ? block.timestamp - u.weightedStartTs : 0;
        return (
            u.registered,
            u.registeredBalance,
            u.weightedStartTs,
            elapsed,
            u.registeredAt,
            u.nextSettlementIdx,
            u.totalClaimed,
            u.registered ? _computePending(u) : 0
        );
    }

    /**
     * @notice Number of settlements created so far.
     */
    function settlementCount() external view returns (uint256) {
        return settlements.length;
    }

    /**
     * @notice Number of currently registered (active) users.
     */
    function activeRegisteredCount() external view returns (uint256) {
        uint256 count = 0;
        for (uint256 i = 0; i < registeredList.length; i++) {
            if (users[registeredList[i]].registered) count++;
        }
        return count;
    }

    // ─── Owner config ────────────────────────────────────────────────────────

    function setTaxReceiver(address _taxReceiver) external onlyOwner {
        emit TaxReceiverUpdated(taxReceiver, _taxReceiver);
        taxReceiver = _taxReceiver;
    }

    function setMinimumBalance(uint256 _minimumBalance) external onlyOwner {
        emit MinimumBalanceUpdated(minimumBalance, _minimumBalance);
        minimumBalance = _minimumBalance;
    }

    /**
     * @notice Emergency rescue: withdraw all BNB to owner.
     *         Only for catastrophic scenarios (e.g. contract bug found).
     */
    function emergencyWithdraw() external onlyOwner nonReentrant {
        uint256 bal = address(this).balance;
        if (bal == 0) revert NothingToClaim();
        (bool ok, ) = owner().call{value: bal}("");
        if (!ok) revert TransferFailed();
    }

    // ─── Internal ────────────────────────────────────────────────────────────

    /**
     * @dev Compute pending BNB for a user across all unclaimed settlements.
     *      For each settlement i ≥ user.nextSettlementIdx:
     *        - If settlement.settledAt ≤ user.weightedStartTs: user wasn't registered → 0
     *        - Else: user's share = (balance × elapsed) / totalWeight × bnbAmount
     */
    function _computePending(UserInfo storage u) internal view returns (uint256) {
        uint256 payout = 0;
        uint256 len    = settlements.length;

        for (uint256 i = u.nextSettlementIdx; i < len; i++) {
            Settlement memory s = settlements[i];

            if (s.settledAt <= u.weightedStartTs) continue; // user wasn't registered yet

            uint256 elapsed = s.settledAt - u.weightedStartTs;
            uint256 userW   = u.registeredBalance * elapsed;

            if (s.totalWeight > 0 && userW > 0) {
                payout += (userW * s.bnbAmount) / s.totalWeight;
            }
        }

        return payout;
    }

    /**
     * @dev Compute the sum of (balance × elapsed) for all active registered users.
     *      O(n) — acceptable for Phase 1 with small user count.
     *      Called once per settlement; NOT called on claim/register/updateBalance.
     */
    function _computeTotalWeight() internal view returns (uint256) {
        uint256 total = 0;
        uint256 now_  = block.timestamp;
        uint256 len   = registeredList.length;

        for (uint256 i = 0; i < len; i++) {
            address addr = registeredList[i];
            UserInfo storage u = users[addr];
            if (!u.registered) continue;
            uint256 elapsed = now_ > u.weightedStartTs ? now_ - u.weightedStartTs : 0;
            total += u.registeredBalance * elapsed;
        }

        return total;
    }

    /**
     * @dev Invalidate a user: compute their forfeited pending, add to forfeitedPool,
     *      remove from pool. The forfeited BNB is swept into the next settlement.
     */
    function _invalidate(address user, UserInfo storage u) internal {
        uint256 forfeited = _computePending(u);
        if (forfeited > 0) {
            forfeitedPool += forfeited;
        }

        totalRegisteredBalance -= u.registeredBalance;
        delete users[user];

        emit Invalidated(user, forfeited);
    }

    function _transferBnb(address to, uint256 amount) internal {
        (bool ok, ) = to.call{value: amount}("");
        if (!ok) revert TransferFailed();
    }
}

contracts/LPRewardVault.sol.content:
// SPDX-License-Identifier: MIT
/// @custom:status ARCHIVED — superseded by BottomProtectionVault (v2 three-route tax model, 40/30/30).
/// Do NOT deploy. Kept for historical reference only.
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/**
 * @title LPRewardVault
 * @notice Phase 1: deployed & accumulates BNB, staking NOT active until token graduates.
 *         Phase 2: owner calls activate(_lpToken) after DEX launch to enable staking.
 *
 * Frontend display:
 *   active == false  → "Deployed / Not Activated (Awaiting Graduation)"
 *   active == true   → LP staking & reward claim enabled
 *
 * Deploy order: deploy after HolderDividend & TaxReceiver.
 *   Constructor only needs owner address — no LP token required until graduation.
 */
contract LPRewardVault is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // ─── State ────────────────────────────────────────────────────────────────
    IERC20 public lpToken;       // set by activate(); zero until graduation
    bool   public active;        // false until activate() is called

    uint256 public totalStaked;
    uint256 public accRewardPerShare;
    uint256 public pendingRewards;  // BNB queued while totalStaked == 0
    uint256 public totalReceived;
    uint256 public totalDistributed;
    uint256 public constant PRECISION = 1e18;

    struct UserInfo {
        uint256 amount;
        uint256 rewardDebt;
    }

    mapping(address => UserInfo) public userInfo;

    // ─── Events ───────────────────────────────────────────────────────────────
    event Activated(address indexed lpToken);
    event Staked(address indexed user, uint256 amount);
    event Unstaked(address indexed user, uint256 amount);
    event Claimed(address indexed user, uint256 reward);
    event RewardAdded(uint256 amount);
    event EmergencyWithdrawn(address indexed to, uint256 amount);

    // ─── Errors ───────────────────────────────────────────────────────────────
    error NotActive();
    error AlreadyActive();
    error ZeroAddress();
    error ZeroAmount();
    error InsufficientStake();
    error NothingToClaim();
    error TransferFailed();

    // ─── Constructor ─────────────────────────────────────────────────────────
    /**
     * @param _owner Deployer / multisig. LP token is set later via activate().
     */
    constructor(address _owner) Ownable(_owner) {
        active = false;
    }

    // ─── BNB receive ─────────────────────────────────────────────────────────
    receive() external payable {
        totalReceived += msg.value;
        if (totalStaked > 0) {
            uint256 total = msg.value + pendingRewards;
            pendingRewards = 0;
            accRewardPerShare += (total * PRECISION) / totalStaked;
        } else {
            pendingRewards += msg.value;
        }
        emit RewardAdded(msg.value);
    }

    fallback() external payable {
        totalReceived += msg.value;
        pendingRewards += msg.value;
        emit RewardAdded(msg.value);
    }

    // ─── Activation (Phase 2) ────────────────────────────────────────────────
    /**
     * @notice Owner activates LP staking after token graduates to DEX.
     * @param _lpToken PancakeSwap CNOVA/WBNB LP token address.
     */
    function activate(address _lpToken) external onlyOwner {
        if (active) revert AlreadyActive();
        if (_lpToken == address(0)) revert ZeroAddress();
        lpToken = IERC20(_lpToken);
        active  = true;
        emit Activated(_lpToken);
    }

    // ─── Staking (Phase 2 only) ───────────────────────────────────────────────
    function stake(uint256 _amount) external nonReentrant {
        if (!active) revert NotActive();
        if (_amount == 0) revert ZeroAmount();

        UserInfo storage u = userInfo[msg.sender];

        if (u.amount > 0) {
            uint256 pend = _pendingReward(u);
            if (pend > 0) {
                totalDistributed += pend;
                _safeTransferBNB(msg.sender, pend);
                emit Claimed(msg.sender, pend);
            }
        }

        lpToken.safeTransferFrom(msg.sender, address(this), _amount);
        u.amount     += _amount;
        totalStaked  += _amount;

        // Absorb any pending BNB now that staked > 0
        if (pendingRewards > 0 && totalStaked > 0) {
            accRewardPerShare += (pendingRewards * PRECISION) / totalStaked;
            pendingRewards = 0;
        }

        u.rewardDebt = (u.amount * accRewardPerShare) / PRECISION;
        emit Staked(msg.sender, _amount);
    }

    function unstake(uint256 _amount) external nonReentrant {
        if (!active) revert NotActive();
        UserInfo storage u = userInfo[msg.sender];
        if (u.amount < _amount) revert InsufficientStake();
        if (_amount == 0) revert ZeroAmount();

        uint256 pend = _pendingReward(u);
        if (pend > 0) {
            totalDistributed += pend;
            _safeTransferBNB(msg.sender, pend);
            emit Claimed(msg.sender, pend);
        }

        u.amount    -= _amount;
        totalStaked -= _amount;
        u.rewardDebt = (u.amount * accRewardPerShare) / PRECISION;
        lpToken.safeTransfer(msg.sender, _amount);
        emit Unstaked(msg.sender, _amount);
    }

    function claim() external nonReentrant {
        if (!active) revert NotActive();
        UserInfo storage u = userInfo[msg.sender];
        uint256 pend = _pendingReward(u);
        if (pend == 0) revert NothingToClaim();
        totalDistributed += pend;
        u.rewardDebt = (u.amount * accRewardPerShare) / PRECISION;
        _safeTransferBNB(msg.sender, pend);
        emit Claimed(msg.sender, pend);
    }

    // ─── Views ────────────────────────────────────────────────────────────────
    function earned(address _user) external view returns (uint256) {
        return _pendingReward(userInfo[_user]);
    }

    function accumulatedBnb() external view returns (uint256) {
        return address(this).balance;
    }

    // ─── Emergency ────────────────────────────────────────────────────────────
    function emergencyWithdraw() external onlyOwner nonReentrant {
        uint256 bal = address(this).balance;
        if (bal == 0) revert NothingToClaim();
        (bool ok, ) = owner().call{value: bal}("");
        if (!ok) revert TransferFailed();
        emit EmergencyWithdrawn(owner(), bal);
    }

    // ─── Internal ─────────────────────────────────────────────────────────────
    function _pendingReward(UserInfo storage u) internal view returns (uint256) {
        if (u.amount == 0) return 0;
        return (u.amount * accRewardPerShare) / PRECISION - u.rewardDebt;
    }

    function _safeTransferBNB(address to, uint256 amount) internal {
        (bool ok, ) = to.call{value: amount}("");
        if (!ok) revert TransferFailed();
    }
}

